+}
+
+export interface AlgorithmStats {
+  algorithm: LearningAlgorithm;
+  updates: number;
+  avgReward: number;
+  convergenceScore: number;
+  lastUpdate: number;
+}
+
+// Default configs for each task type
+const TASK_ALGORITHM_MAP: Record<TaskType, LearningConfig> = {
+  'agent-routing': {
+    algorithm: 'double-q',
+    learningRate: 0.1,
+    discountFactor: 0.95,
