+    // Initialize stats for all algorithms
+    const algorithms: LearningAlgorithm[] = [
+      'q-learning', 'sarsa', 'double-q', 'actor-critic',
+      'ppo', 'decision-transformer', 'monte-carlo', 'td-lambda', 'dqn'
