+  /**
+   * Check if tensor exists
+   */
+  has(id: string): boolean {
+    return this.tensors.has(id);
+  }
+
+  /**
+   * Delete a tensor
+   */
+  delete(id: string): boolean {
+    return this.tensors.delete(id);
+  }
+
+  /**
+   * Get all tensor IDs
