+  }
+
+  /**
+   * Compress tensor to specified level
+   */
+  private compress(data: number[], level: CompressionLevel): { data: any; level: CompressionLevel } {
+    switch (level) {
+      case 'none':
+        return { data: new Float32Array(data), level };
