+    return output;
+  }
+
+  private fromPQ8(data: Uint8Array, dim: number): Float32Array {
+    const view = new DataView(data.buffer, data.byteOffset);
+    const min = view.getFloat32(0, true);
+    const max = view.getFloat32(4, true);
+    const range = max - min || 1;
