+    const min = Math.min(...data);
+    const max = Math.max(...data);
+    const range = max - min || 1;
+
+    const view = new DataView(result.buffer);
+    view.setFloat32(0, min, true);
+    view.setFloat32(4, max, true);
+
+    for (let i = 0; i < data.length; i += 2) {
