+    for (let i = 0; i < data.length; i++) {
+      if (data[i] >= mean) {
+        const byteIdx = 4 + Math.floor(i / 8);
+        const bitIdx = i % 8;
+        result[byteIdx] |= (1 << bitIdx);
+      }
+    }
